module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const color = args.color || 'var(--accent-color)';
const pie = String(args.style) === 'pie';
const showPct = String(args.showpercent) === 'true';
const size = String(args.size || 'normal').toLowerCase();
const dims = size === 'small' ? { bw: '120px', bh: '24px', pie: '60px' }
  : size === 'large' ? { bw: '240px', bh: '40px', pie: '120px' }
  : { bw: '180px', bh: '30px', pie: '90px' };
const align = String(args.align || 'left').toLowerCase();
const justify = align === 'center' ? 'center' : align === 'right' ? 'flex-end' : 'flex-start';
const items = [];
sections.map((s) => (s || '').trim()).filter(Boolean).forEach((s) => {
  const m = s.match(/^(\d+)\s*\/\s*(\d+)\s*([\s\S]*)$/);
  if (m) items.push({ n: parseInt(m[1], 10), d: Math.max(1, parseInt(m[2], 10)), label: m[3].trim() });
});
if (!items.length) return `<div>(fracbar: "n/d label" per section)</div>`;
let html = `\n\n<div class="mdp-mod-fracbar" style="--fb-c:${color}; --fb-bw:${dims.bw}; --fb-bh:${dims.bh}; --fb-pie:${dims.pie}; justify-content:${justify};">`;
items.forEach((it) => {
  const n = Math.min(it.n, it.d);
  html += `<div class="mdp-fb-item">`;
  if (pie) {
    const degs = (n / it.d) * 360;
    html += `<div class="mdp-fb-pie" style="background: conic-gradient(var(--fb-c) 0deg ${degs.toFixed(1)}deg, color-mix(in srgb, currentColor 10%, transparent) ${degs.toFixed(1)}deg 360deg);"></div>`;
  } else {
    html += `<div class="mdp-fb-bar">`;
    for (let i = 0; i < it.d; i++) html += `<div class="mdp-fb-seg${i < n ? ' on' : ''}"></div>`;
    html += `</div>`;
  }
  const pct = showPct ? ` <span class="mdp-fb-pct">${Math.round((n / it.d) * 100)}%</span>` : '';
  html += `<div class="mdp-fb-caption"><span class="mdp-fb-frac"><sup>${it.n}</sup>⁄<sub>${it.d}</sub></span>` +
    (it.label ? ` <span class="mdp-fb-label">${esc(it.label)}</span>` : '') + pct + `</div></div>`;
});
html += `</div>\n\n`;
return html;
